// MARK: - Universal Link Validator

struct UniversalLinkValidator {
    
    // Strict allowlist of accepted hosts
    private static let allowedHosts: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    // Strict allowlist of accepted paths for promo handling
    private static let allowedPromoPaths: Set<String> = [
        "/promo"
    ]
    
    // Allowed URL schemes
    private static let allowedSchemes: Set<String> = [
        "https"
    ]
    
    enum ValidationError: Error, CustomStringConvertible {
        case invalidURL
        case disallowedScheme(String?)
        case disallowedHost(String?)
        case disallowedPath(String)
        case missingRequiredParameter(String)
        case invalidParameterValue(parameter: String, value: String)
        case userNotAuthenticated
        case rateLimited
        
        var description: String {
            switch self {
            case .invalidURL:
                return "The URL is invalid."
            case .disallowedScheme(let scheme):
                return "Disallowed URL scheme: \(scheme ?? "nil")"
            case .disallowedHost(let host):
                return "Disallowed host: \(host ?? "nil")"
            case .disallowedPath(let path):
                return "Disallowed path: \(path)"
            case .missingRequiredParameter(let param):
                return "Missing required parameter: \(param)"
            case .invalidParameterValue(let param, let value):
                return "Invalid value '\(value)' for parameter '\(param)'"
            case .userNotAuthenticated:
                return "User must be authenticated to use promo links."
            case .rateLimited:
                return "Too many promo attempts. Please try again later."
            }
        }
    }
    
    struct ValidatedPromoLink {
        let code: String
        let discount: Int
    }
    
    static func validatePromoLink(url: URL) -> Result<ValidatedPromoLink, ValidationError> {
        // 1. Validate scheme
        guard let scheme = url.scheme?.lowercased(), allowedSchemes.contains(scheme) else {
            return .failure(.disallowedScheme(url.scheme))
        }
        
        // 2. Validate host against strict allowlist
        guard let host = url.host?.lowercased(), allowedHosts.contains(host) else {
            return .failure(.disallowedHost(url.host))
        }
        
        // 3. Validate path against strict allowlist (normalize by removing trailing slash)
        let normalizedPath = url.path.hasSuffix("/") && url.path.count > 1
            ? String(url.path.dropLast())
            : url.path
        
        guard allowedPromoPaths.contains(normalizedPath.lowercased()) else {
            return .failure(.disallowedPath(normalizedPath))
        }
        
        // 4. Parse and validate query parameters
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.invalidURL)
        }
        
        let queryItems = components.queryItems ?? []
        let queryDict = Dictionary(queryItems.compactMap { item -> (String, String)? in
            guard let value = item.value else { return nil }
            return (item.name, value)
        }, uniquingKeysWith: { first, _ in first })
        
        // 5. Validate required 'code' parameter
        guard let code = queryDict["code"], !code.isEmpty else {
            return .failure(.missingRequiredParameter("code"))
        }
        
        // Validate code format: alphanumeric, 3-20 characters
        let codePattern = "^[A-Z0-9]{3,20}$"
        guard let codeRegex = try? NSRegularExpression(pattern: codePattern, options: []),
              codeRegex.firstMatch(in: code.uppercased(), options: [], range: NSRange(location: 0, length: code.utf16.count)) != nil else {
            return .failure(.invalidParameterValue(parameter: "code", value: code))
        }
        
        // 6. Validate required 'discount' parameter
        guard let discountString = queryDict["discount"], !discountString.isEmpty else {
            return .failure(.missingRequiredParameter("discount"))
        }
        
        // Validate discount is a valid integer in acceptable range
        guard let discount = Int(discountString), discount >= 1, discount <= 75 else {
            return .failure(.invalidParameterValue(parameter: "discount", value: discountString))
        }
        
        // 7. Check for unexpected/extraneous parameters (defense in depth)
        let allowedParams: Set<String> = ["code", "discount", "utm_source", "utm_medium", "utm_campaign", "utm_content", "utm_term"]
        let providedParams = Set(queryItems.map { $0.name })
        let unexpectedParams = providedParams.subtracting(allowedParams)
        if !unexpectedParams.isEmpty {
            // Log unexpected parameters but don't necessarily fail — just ignore them
            print("[Security] Unexpected URL parameters ignored: \(unexpectedParams)")
        }
        
        return .success(ValidatedPromoLink(code: code.uppercased(), discount: discount))
    }
}

// MARK: - Rate Limiter

class RateLimiter {
    static let shared = RateLimiter()
    
    private var attempts: [String: [Date]] = [:]
    private let maxAttempts = 5
    private let windowSeconds: TimeInterval = 300 // 5 minutes
    private let queue = DispatchQueue(label: "com.myapp.ratelimiter", attributes: .concurrent)
    
    private init() {}
    
    func isAllowed(for identifier: String) -> Bool {
        var allowed = false
        queue.sync {
            let now = Date()
            let windowStart = now.addingTimeInterval(-windowSeconds)
            
            var userAttempts = attempts[identifier] ?? []
            userAttempts = userAttempts.filter { $0 > windowStart }
            
            if userAttempts.count < maxAttempts {
                allowed = true
            }
        }
        return allowed
    }
    
    func recordAttempt(for identifier: String) {
        queue.async(flags: .barrier) {
            var userAttempts = self.attempts[identifier] ?? []
            userAttempts.append(Date())
            
            let windowStart = Date().addingTimeInterval(-self.windowSeconds)
            userAttempts = userAttempts.filter { $0 > windowStart }
            
            self.attempts[identifier] = userAttempts
        }
    }
}

