class PromoViewController: UIViewController {
    
    private let promoCodeLabel = UILabel()
    private let discountLabel = UILabel()
    private let statusLabel = UILabel()
    private let applyButton = UIButton(type: .system)
    private let activityIndicator = UIActivityIndicatorView(style: .large)
    
    private var promoCode: String = ""
    private var discountPercentage: Int = 0
    
    func configure(code: String, discount: Int) {
        self.promoCode = code
        self.discountPercentage = discount
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        updateDisplay()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Apply Promo Code"
        
        promoCodeLabel.font = UIFont.systemFont(ofSize: 28, weight: .bold)
        promoCodeLabel.textAlignment = .center
        promoCodeLabel.textColor = .label
        
        discountLabel.font = UIFont.systemFont(ofSize: 22, weight: .medium)
        discountLabel.textAlignment = .center
        discountLabel.textColor = .systemGreen
        
        statusLabel.font = UIFont.systemFont(ofSize: 16, weight: .regular)
        statusLabel.textAlignment = .center
        statusLabel.textColor = .secondaryLabel
        statusLabel.numberOfLines = 0
        
        applyButton.setTitle("Apply Promo Code", for: .normal)
        applyButton.titleLabel?.font = UIFont.systemFont(ofSize: 18, weight: .semibold)
        applyButton.backgroundColor = .systemBlue
        applyButton.setTitleColor(.white, for: .normal)
        applyButton.layer.cornerRadius = 12
        applyButton.addTarget(self, action: #selector(applyPromoTapped), for: .touchUpInside)
        
        activityIndicator.hidesWhenStopped = true
        
        let stackView = UIStackView(arrangedSubviews: [promoCodeLabel, discountLabel, statusLabel, applyButton, activityIndicator])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.alignment = .center
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            applyButton.heightAnchor.constraint(equalToConstant: 50),
            applyButton.widthAnchor.constraint(equalTo: stackView.widthAnchor)
        ])
    }
    
    private func updateDisplay() {
        promoCodeLabel.text = "Code: \(promoCode)"
        discountLabel.text = "Up to \(discountPercentage)% Off"
        statusLabel.text = "Tap below to apply this promotional discount to your account. Final discount determined by server."
    }
    
    @objc private func applyPromoTapped() {
        guard AuthService.shared.isAuthenticated, let userId = AuthService.shared.currentUserId else {
            showAlert(title: "Authentication Required", message: "Please log in to apply promo codes.")
            return
        }
        
        // Rate limiting check
        guard RateLimiter.shared.isAllowed(for: userId) else {
            showAlert(title: "Too Many Attempts", message: "Please wait a few minutes before trying again.")
            return
        }
        
        RateLimiter.shared.recordAttempt(for: userId)
        
        applyButton.isEnabled = false
        activityIndicator.startAnimating()
        statusLabel.text = "Validating with server..."
        
        PromoService.shared.validateAndApplyPromo(code: promoCode, discount: discountPercentage, forUser: userId) { [weak self] result in
            guard let self = self else { return }
            
            self.activityIndicator.stopAnimating()
            self.applyButton.isEnabled = true
            
            if result.success {
                self.statusLabel.textColor = .systemGreen
                self.statusLabel.text = result.message
                self.applyButton.isEnabled = false
                self.applyButton.backgroundColor = .systemGray
                self.applyButton.setTitle("Applied ✓", for: .normal)
            } else {
                self.statusLabel.textColor = .systemRed
                self.statusLabel.text = result.message
            }
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

// MARK: - Scene Delegate (Universal Link Handling)

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        window = UIWindow(windowScene: windowScene)
        let rootVC = UINavigationController(rootViewController: HomeViewController())
        window?.rootViewController = rootVC
        window?.makeKeyAndVisible()
        
        // Handle universal link if app was launched via one
        if let userActivity = connectionOptions.userActivities.first(where: { $0.activityType == NSUserActivityTypeBrowsingWeb }) {
            handleUniversalLink(userActivity: userActivity)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        handleUniversalLink(userActivity: userActivity)
    }
    
    private func handleUniversalLink(userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            logSecurityEvent(event: "universal_link_rejected", details: "Invalid activity type or missing URL")
            return
        }
        
        logSecurityEvent(event: "universal_link_received", details: "URL: \(url.absoluteString)")
        
        // Validate the universal link using strict allowlist-based validation
        let validationResult = UniversalLinkValidator.validatePromoLink(url: url)
        
        switch validationResult {
        case .success(let validatedPromo):
            // Authorization check: user must be authenticated
            if AuthService.shared.isAuthenticated {
                // Rate limiting at the link handling level
                guard let userId = AuthService.shared.currentUserId,
                      RateLimiter.shared.isAllowed(for: userId) else {
                    logSecurityEvent(event: "promo_rate_limited", details: "User rate limited for promo: \(validatedPromo.code)")
                    showErrorAlert(message: "Too many promo attempts. Please try again later.")
                    return
                }
                
                presentPromoScreen(code: validatedPromo.code, discount: validatedPromo.discount)
            } else {
                // Store the validated promo for after authentication
                PendingPromoStore.shared.storePending(validatedPromo)
                logSecurityEvent(event: "promo_deferred", details: "User not authenticated, storing promo: \(validatedPromo.code)")
                promptLogin(message: "Please log in to apply your promo code: \(validatedPromo.code)")
            }
            
        case .failure(let error):
            logSecurityEvent(event: "universal_link_validation_failed", details: "\(error)")
            // Don't reveal specific validation failure details to the user
            showErrorAlert(message: "This promotional link is not valid. Please check the link and try again.")
        }
    }
    
    private func presentPromoScreen(code: String, discount: Int) {
        guard let navController = window?.rootViewController as? UINavigationController else { return }
        
        let promoVC = PromoViewController()
        promoVC.configure(code: code, discount: discount)
        
        DispatchQueue.main.async {
            navController.pushViewController(promoVC, animated: true)
        }
    }
    
    private func promptLogin(message: String) {
        guard let rootVC = window?.rootViewController else { return }
        
        let alert = UIAlertController(title: "Login Required", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Log In", style: .default) { _ in
            // Navigate to login screen
            // After successful login, check PendingPromoStore and apply
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        DispatchQueue.main.async {
            rootVC.present(alert, animated: true)
        }
    }
    
    private func showErrorAlert(message: String) {
        guard let rootVC = window?.rootViewController else { return }
        
        let alert = UIAlertController(title: "Invalid Link", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        DispatchQueue.main.async {
            rootVC.present(alert, animated: true)
        }
    }
    
    private func logSecurityEvent(event: String, details: String) {
        // In production, send to your security logging/monitoring service
        let timestamp = ISO8601DateFormatter().string(from: Date())
        let userId = AuthService.shared.currentUserId ?? "unauthenticated"
        print("[SECURITY][\(timestamp)] event=\(event) user=\(userId) details=\(details)")
    }
}

// MARK: - Home View Controller

class HomeViewController: UIViewController {
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        title = "My App"
        
        let label = UILabel()
        label.text = "Welcome to MyApp"
        label.font = UIFont.systemFont(ofSize: 24, weight: .bold)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(label)
        NSLayoutConstraint.activate([
            label.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            label.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
        
        // Check for pending promo after login
        NotificationCenter.default.addObserver(self, selector: #selector(checkPendingPromo), name: .userDidAuthenticate, object: nil)
    }
    
    @objc private func checkPendingPromo() {
        if let pendingPromo = PendingPromoStore.shared.consumePending() {
            let promoVC = PromoViewController()
            promoVC.configure(code: pendingPromo.code, discount: pendingPromo.discount)
            navigationController?.pushViewController(promoVC, animated: true)
        }
    }
}

